async (params, browser) => {
  // Open page
  await browser.open(`https://huggingface.co/${params.category}?sort=trending`)

  // Wait for content
  await browser.waitForSelector('h4, article', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const items = []; const cards = document.querySelectorAll('article, main a[href]:has(h4)'); for (let i = 0; i < Math.min(cards.length, 20); i++) { const card = cards[i]; const titleEl = card.querySelector('h4'); if (!titleEl) continue; const spans = Array.from(card.querySelectorAll('span')); const link = card.closest('a[href]') || card.querySelector('a[href]') || card; items.push({ rank: items.length + 1, name: titleEl.textContent.trim(), url: link.href || '', meta: spans.slice(0, 5).map(s => s.textContent.trim()).filter(Boolean) }); } return { category: '' + params.category + '', items }`)

  return page_data
}
